import { Hound, HoundManagement } from 'hound/';

const hound = Hound.create({ db: redis, auth: 'my-secret-token' });
const mgmt = new HoundManagement({ db: redis, hound });

await hound.start();
hound.listen(4000, mgmt, () => console.log('Gateway on :4000'));

import { createGateway } from 'hound/';

createGateway({
  port: 4000,
  hostname: '0.0.0.0',
  hound,
  management: mgmt,
  auth: 'my-secret-token',
});

const hound = Hound.create({
  db: redis,
  auth: Deno.env.get('HOUND_TOKEN'),
});

import { generateClient } from 'hound/';

// Run once to generate the client file
await generateClient(hound, {
  outputPath: './gen/hound-client.ts',
  gatewayUrl: 'http://localhost:4000',
  token: Deno.env.get('HOUND_TOKEN'),
});
